const topSongsByArtistName = `-- name: TopSongsByArtistName :many
WITH RECURSIVE shared_subtree AS (
    SELECT resource_id AS node_id FROM resource_shares
    WHERE resource_type = 'file_node' AND shared_with_user = $1::uuid
      AND (expires_at IS NULL OR expires_at > now())
    UNION
    SELECT n.id FROM nodes n JOIN shared_subtree st ON n.parent_id = st.node_id
)
SELECT s.id, s.user_id, s.album_id, s.artist_id, s.node_id, s.title, s.track, s.disc, s.duration, s.bitrate, s.suffix, s.content_type, s.size, s.genre, s.musicbrainz_id, s.created_at, s.updated_at, al.name AS album_name, ar.name AS artist_name, al.year AS album_year,
       COUNT(ph.id) AS play_count
FROM songs s
JOIN albums al ON al.id = s.album_id
JOIN artists ar ON ar.id = s.artist_id
LEFT JOIN play_history ph ON ph.song_id = s.id AND ph.user_id = $1
WHERE lower(ar.name) = lower($2)
  AND (s.user_id = $1 OR s.node_id IN (SELECT node_id FROM shared_subtree))
GROUP BY s.id, al.name, ar.name, al.year
ORDER BY play_count DESC, s.title
LIMIT $3
`

